sections.chart_script:
(function(){
            var dk = matchMedia('(prefers-color-scheme: dark)').matches;
            var gc = dk ? 'rgba(255,255,255,0.06)' : 'rgba(0,0,0,0.06)';
            var tc = dk ? 'rgba(255,255,255,0.4)' : 'rgba(0,0,0,0.45)';
            function yFmt(v){ return '$' + v + 'B'; }
            new Chart(document.getElementById('ch1'), {
              type:'line', data:{ labels:['2021','2022','2023','2024','2025'], datasets:[
                { label:'Meta', data:[115,114,132,157,201], borderColor:'#378ADD', backgroundColor:'rgba(55,138,221,0.07)', tension:0.35, borderWidth:2, pointRadius:4, fill:true },
                { label:'YouTube total', data:[29,29,31,54,60], borderColor:'#1D9E75', backgroundColor:'rgba(29,158,117,0.07)', tension:0.35, borderWidth:2, pointRadius:4, fill:true },
                { label:'YouTube ads', data:[20,21,22,36,40], borderColor:'#97C459', backgroundColor:'transparent', tension:0.35, borderWidth:1.5, pointRadius:3, fill:false, borderDash:[4,3] }
              ]},
              options:{ responsive:true, maintainAspectRatio:false, plugins:{ legend:{ display:false } }, scales:{ x:{ grid:{ color:gc }, ticks:{ color:tc, font:{ size:11 } } }, y:{ min:0, grid:{ color:gc }, ticks:{ color:tc, font:{ size:11 }, callback:yFmt } } } }
            });
            new Chart(document.getElementById('ch2'), {
              type:'bar', data:{ labels:['2019','2021','2022','2023','2024','2025'], datasets:[
                { label:'Ad revenue', data:[15,20,21,22,36,40], backgroundColor:'#378ADD', borderRadius:3 },
                { label:'Subscriptions', data:[3,9,11,15,15,20], backgroundColor:'#7F77DD', borderRadius:3 }
              ]},
              options:{ responsive:true, maintainAspectRatio:false, plugins:{ legend:{ display:false } }, scales:{ x:{ stacked:true, grid:{ color:gc }, ticks:{ color:tc, font:{ size:11 } } }, y:{ stacked:true, grid:{ color:gc }, ticks:{ color:tc, font:{ size:11 }, callback:yFmt } } } }
            });
            new Chart(document.getElementById('ch3'), {
              type:'bar', data:{ labels:['CTV premium','YouTube long-form','Instagram Reels','YouTube Shorts'], datasets:[{ label:'Avg CPM', data:[30,15,10,3.5], backgroundColor:['#378ADD','#1D9E75','#7F77DD','#D85A30'], borderRadius:4 }] },
              options:{ responsive:true, maintainAspectRatio:false, indexAxis:'y', plugins:{ legend:{ display:false } }, scales:{ x:{ grid:{ color:gc }, ticks:{ color:tc, font:{ size:11 }, callback:function(v){ return '$'+v; } } }, y:{ grid:{ display:false }, ticks:{ color:tc, font:{ size:12 } } } } }
            });
          })();
